 1	import type { FC } from 'react';
 2	
 3	import type { V1beta1Plan } from '@kubev2v/types';
 4	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 5	
 6	import { PlanStatuses } from '../../../PlanStatus/utils/types';
 7	import usePlanAlerts from '../../hooks/usePlanAlerts';
 8	import PlanCriticalAlert from '../PlanCriticalAlert';
 9	import PlanPreserveIPWarningsAlerts from '../PlanPreserveIPWarningsAlerts';
10	
11	import './PlanAlerts.scss';
12	
13	type Props = {
14	  plan: V1beta1Plan;
15	};
16	
17	const PlanAlerts: FC<Props> = ({ plan }) => {
18	  const {
19	    criticalCondition,
20	    networkMaps,
21	    networkMapsError,
22	    networkMapsLoaded,
23	    preserveIPWarningsConditions,
24	    showCriticalCondition,
25	    showPreserveIPWarningsConditions,
26	    sourceNetworks,
27	    sourceStorages,
28	    status,
29	    storageMaps,
30	  } = usePlanAlerts(plan);
31	
32	  const alertsNotRelevant = status === PlanStatuses.Completed || status === PlanStatuses.Archived;
33	
34	  if (alertsNotRelevant || !networkMapsLoaded || networkMapsError) {
35	    return null;
36	  }
37	
38	  if (!showCriticalCondition && !showPreserveIPWarningsConditions) {
39	    return null;
40	  }
41	
42	  return (
43	    <PageSection variant={PageSectionVariants.light} className="plan-header-alerts">
44	      {showCriticalCondition && (
45	        <PlanCriticalAlert
46	          plan={plan}
47	          condition={criticalCondition}
48	          storageMaps={storageMaps}
49	          networkMaps={networkMaps}
50	          sourceStorages={sourceStorages}
51	          sourceNetworks={sourceNetworks}
52	        />
53	      )}
54	      {showPreserveIPWarningsConditions && (
55	        <PlanPreserveIPWarningsAlerts plan={plan} conditions={preserveIPWarningsConditions} />
56	      )}
57	    </PageSection>
58	  );
59	};
60	
61	export default PlanAlerts;

